import { useState } from "react";
import { motion, AnimatePresence } from "framer-motion";
import { adminDashboardDesign as design } from "../../design/adminDashboardDesign";

const AdminDashboard = () => {
  const adminInfo = JSON.parse(localStorage.getItem("adminInfo"));
  const [isOpen, setIsOpen] = useState(false);

  return (
    <div className={design.layout.wrapper}>
      
      {/* ✅ Overlay (Mobile Only) */}
      <AnimatePresence>
        {isOpen && (
          <motion.div
            initial={{ opacity: 0 }}
            animate={{ opacity: 1 }}
            exit={{ opacity: 0 }}
            className={`fixed inset-0 z-40 md:hidden ${design.colors.overlay}`}
            onClick={() => setIsOpen(false)}
          />
        )}
      </AnimatePresence>

      {/* ✅ Sidebar */}
      <motion.aside
        initial={false}
        animate={{ x: isOpen ? 0 : -260 }}
        transition={{ duration: 0.3 }}
        className={`${design.colors.sidebar} ${design.layout.sidebar} ${
          isOpen ? "translate-x-0" : "-translate-x-full"
        }`}
      >
        <h2 className="text-2xl font-bold text-indigo-400">
          Admin Panel
        </h2>

        <nav className="space-y-3">
          <div className={`${design.layout.navItem} ${design.colors.hover}`}>
            Dashboard
          </div>
          <div className={`${design.layout.navItem} ${design.colors.hover}`}>
            Products
          </div>
          <div className={`${design.layout.navItem} ${design.colors.hover}`}>
            Orders
          </div>
          <div className={`${design.layout.navItem} ${design.colors.hover}`}>
            Users
          </div>
        </nav>
      </motion.aside>

      {/* ✅ Right Content Area */}
      <div className={design.layout.contentWrapper}>
        
        {/* Navbar */}
        <div className={design.layout.navbar}>
          
          {/* Toggle Button (Mobile Only) */}
          <button
            onClick={() => setIsOpen(!isOpen)}
            className={`md:hidden ${design.colors.toggleBtn}`}
          >
            ☰
          </button>

          <h1 className="font-semibold text-lg hidden md:block">
            Dashboard
          </h1>

          <div className="flex items-center gap-4">
            <span className="text-sm text-gray-600">
              {adminInfo?.name}
            </span>
            <div className="w-8 h-8 bg-indigo-500 rounded-full"></div>
          </div>
        </div>

        {/* Main Content */}
        <div className={design.layout.content}>
          <h2 className="text-2xl font-bold mb-4">
            Welcome Back 👋
          </h2>

          <p className="text-gray-600">
            This is your fully responsive admin dashboard.
          </p>
        </div>
      </div>
    </div>
  );
};

export default AdminDashboard;
